firmware_template.source:
#include "soil_moisture.h"
#include <Arduino.h>
static int _raw=0;static float _pct=0;
static unsigned long _last=0;
#define SOIL_PIN 34
#define DRY_VAL 3500
#define WET_VAL 1500
void soil_moisture_setup(){pinMode(SOIL_PIN,INPUT);Serial.println("[soil] OK");}
void soil_moisture_loop(){
  if(millis()-_last<1000)return;
  _last=millis();
  _raw=analogRead(SOIL_PIN);
  _pct=constrain(map(_raw,DRY_VAL,WET_VAL,0,100),0,100);
  Serial.printf("[soil] %d raw, %.0f%%\n",_raw,_pct);
}
int soil_moisture_get_raw(){return _raw;}
float soil_moisture_get_percent(){return _pct;}
